    24→		double radius = ball.getRadius();
    25→		at.setToTranslation(ball.getLocation().x, ball.getLocation().y);
    26→		at.scale(radius, radius);
    27→		at.rotate(Math.atan2(ball.getVelocity().y, ball.getVelocity().x));
    28→		g.setColor(ball.getColor());
    29→		paintCfg(g, ball);
    30→		paintXfrm(g, ball, at);
    31→	}
